RLTaskSceneEntityHintSchema::Base_typeEnum RLTaskSceneEntityHintSchema::toBase_typeEnum(const utility::string_t& value) const
{
    
    if (value == utility::conversions::to_string_t("fixed")) {
        return Base_typeEnum::FIXED;
    }
    
    if (value == utility::conversions::to_string_t("free")) {
        return Base_typeEnum::FREE;
    }
    
    throw std::invalid_argument("Invalid value for conversion to Base_typeEnum");
}


const utility::string_t RLTaskSceneEntityHintSchema::fromBase_typeEnum(const Base_typeEnum value) const
{
    switch(value)
    {
        
        case Base_typeEnum::FIXED: return utility::conversions::to_string_t("fixed");
        
        case Base_typeEnum::FREE: return utility::conversions::to_string_t("free");
        
    }
}

